   812	func getPersonaLibraryPath(workingDir string) (string, error) {
   813		// Use the config system with working directory parameter
   814		if workingDir == "" {
   815			return "", fmt.Errorf("working directory must be provided")
   816		}
   817	
   818		// Use the library path resolution from config
   819		cfg, err := config.LoadWithWorkingDir(workingDir)
   820		if err != nil {
   821			return "", err
   822		}
   823	
   824		if cfg.Library != nil {
   825			libPath := cfg.Library.Path
   826			// If path is relative, resolve it relative to working directory
   827			if !filepath.IsAbs(libPath) {
   828				libPath = filepath.Join(workingDir, libPath)
   829			}
   830			return libPath, nil
   831		}
   832		return "", fmt.Errorf("library path not configured")
