   854	// personaEdit updates a project-local persona. If bodyFile is empty, it
   855	// opens $EDITOR on the file.
   856	func personaEdit(cmd *cobra.Command, workingDir, name, bodyFile string) (*persona.Persona, error) {
   857		if workingDir == "" {
   858			return nil, fmt.Errorf("working directory must be provided")
   859		}
   860		writer := persona.NewProjectPersonaWriter(workingDir)
   861	
   862		if bodyFile != "" {
   863			body, err := os.ReadFile(bodyFile)
   864			if err != nil {
   865				return nil, fmt.Errorf("failed to read body file %s: %w", bodyFile, err)
   866			}
   867			return writer.Update(name, string(body))
   868		}
   869	
   870		// Interactive edit: open $EDITOR on the project file in place, then
   871		// re-read to validate.
   872		projectFile := filepath.Join(writer.ProjectDir(), name+".md")
   873		if _, err := os.Stat(projectFile); os.IsNotExist(err) {
   874			// Surface the same error the writer would.
   875			if _, err := writer.Update(name, ""); err != nil {
   876				return nil, err
   877			}
   878		}
   879	
   880		editor := os.Getenv("EDITOR")
   881		if editor == "" {
   882			editor = "vi"
   883		}
   884		editCmd := exec.Command(editor, projectFile) // #nosec G204 — intentional $EDITOR invocation
   885		editCmd.Stdin = cmd.InOrStdin()
   886		editCmd.Stdout = cmd.OutOrStdout()
   887		editCmd.Stderr = cmd.ErrOrStderr()
   888		if err := editCmd.Run(); err != nil {
   889			return nil, fmt.Errorf("editor exited with error: %w", err)
   890		}
   891		data, err := os.ReadFile(projectFile)
   892		if err != nil {
   893			return nil, fmt.Errorf("failed to re-read persona after edit: %w", err)
   894		}
   895		return writer.Update(name, string(data))
   896	}
